import pandas as pd
import re
from sentence_transformers import SentenceTransformer, util

class FreeRAGEvaluator:
    def __init__(self, model_name="all-MiniLM-L6-v2"):
        
        self.model = SentenceTransformer(model_name)
    
    def normalize_text(self, text):
        """Làm sạch văn bản để tính toán (viết thường, xóa dấu)."""
        if not isinstance(text, str): return ""
        text = text.lower().strip()
        text = re.sub(r'[^\w\s]', '', text) 
        return text

    def calculate_answer_similarity(self, answer, ground_truth):
        """So sánh ý nghĩa câu trả lời AI với đáp án mẫu."""
        emb1 = self.model.encode(str(answer), convert_to_tensor=True)
        emb2 = self.model.encode(str(ground_truth), convert_to_tensor=True)
        return util.cos_sim(emb1, emb2).item()

    def calculate_context_recall(self, contexts, ground_truth):
        """Recall: Đáp án có nằm trong tài liệu tìm được không?"""
        gt_norm = self.normalize_text(ground_truth)
        full_context = " ".join([self.normalize_text(c) for c in contexts])
        
        if gt_norm in full_context: return 1.0
        
        gt_tokens = set(gt_norm.split())
        ctx_tokens = set(full_context.split())
        if not gt_tokens: return 0.0
        
        match_count = len(gt_tokens.intersection(ctx_tokens))
        return match_count / len(gt_tokens)

    def calculate_context_precision(self, contexts, ground_truth):
        """Precision: Tỷ lệ các đoạn văn hữu ích."""
        gt_norm = self.normalize_text(ground_truth)
        relevant_chunks = 0
  
        for ctx in contexts:
            ctx_norm = self.normalize_text(ctx)
            if gt_norm in ctx_norm:
                relevant_chunks += 1
            else:
                gt_tokens = set(gt_norm.split())
                ctx_tokens = set(ctx_norm.split())
                if len(gt_tokens) > 0:
                    overlap = len(gt_tokens.intersection(ctx_tokens)) / len(gt_tokens)
                    if overlap > 0.7: 
                        relevant_chunks += 1

        if len(contexts) == 0: return 0.0
        return relevant_chunks / len(contexts)

    def evaluate(self, dataset):
        results = []
        print(f"🚀 Đang chạy đánh giá trên {len(dataset)} câu hỏi...")
        
        for i, item in enumerate(dataset):
            question = item['question']
            answer = item['answer']
            contexts = item['contexts']
            ground_truth = item['ground_truth']

            # Tính toán điểm số
            sim_score = self.calculate_answer_similarity(answer, ground_truth)
            recall_score = self.calculate_context_recall(contexts, ground_truth)
            precision_score = self.calculate_context_precision(contexts, ground_truth)

            # Thêm đầy đủ các cột vào kết quả
            results.append({
                "Question": question,
                "Answer": answer,
                "Ground Truth": ground_truth,
                "Contexts": "\n---\n".join(contexts), # Nối các đoạn văn lại cho dễ đọc
                "Answer Similarity": round(sim_score, 3),
                "Context Recall": round(recall_score, 3),
                "Context Precision": round(precision_score, 3)
            })
            
        return pd.DataFrame(results)

