# 2. Khởi tạo và chạy đánh giá
evaluator = FreeRAGEvaluator()
df_results = evaluator.evaluate(data)

# 3. Tính điểm trung bình và thêm dòng cuối
means = df_results[["Answer Similarity", "Context Recall", "Context Precision"]].mean()
print("\n📊 ĐIỂM TRUNG BÌNH TOÀN HỆ THỐNG:")
print(means)

# Tạo dòng trung bình để thêm vào DataFrame
avg_row = {
    "Question": "TRUNG BÌNH (AVERAGE)",
    "Answer": "",
    "Ground Truth": "",
    "Contexts": "",
    "Answer Similarity": round(means["Answer Similarity"], 3),
    "Context Recall": round(means["Context Recall"], 3),
    "Context Precision": round(means["Context Precision"], 3)
}

# Nối dòng trung bình vào cuối bảng
df_final = pd.concat([df_results, pd.DataFrame([avg_row])], ignore_index=True)

# 4. Xuất file CSV (Sửa lỗi font tiếng Việt)
filename = "rag_optimized_score.csv"
# encoding='utf-8-sig' là chìa khóa để Excel hiển thị đúng tiếng Việt
df_final.to_csv(filename, index=False, encoding='utf-8-sig')

print(f"\n✅ Đã lưu kết quả (đầy đủ cột + tiếng Việt) vào file: {filename}")